from cache_sim import Sim, synth_traces

# 1) fits-in-window policy at toy B=1: prefetch only if the fetch fits the window
class FitSim(Sim):
    def prefetch(self, tok0, l):
        if self.FETCH_MS > self.T_LAYER*self.B: return
        super().prefetch(tok0, l)

import numpy as np
for f in ('traces_base.npz','traces_joint.npz'):
    d=np.load(f); lab=f.split('_')[1][:5]
    for pol in (1,4):
        r=FitSim(d['true_topk'], d[f'pred_h{pol}'], 64, pol, 1).run()
        print(f'fit-window {lab} B=1 C=64 h{pol}: tok/s={r[\"tok_s\"]:.1f} (demand=85.8/86.1, naive=62.7/71.4)')

